const items = $input.all();

// ---- Extract current metrics (item 0) ----
const currentRaw = items[0]?.json || {};
const currentMetrics = {};

for (const [key, value] of Object.entries(currentRaw)) {
  if (key !== "row_number") {
    currentMetrics[key] = Number(value) || 0;
  }
}

// ---- Extract previous metrics (item 1) ----
let previousMetrics = {};
const previousItem = items[1]?.json;

if (previousItem && previousItem["Metrics JSON"]) {
  const raw = previousItem["Metrics JSON"];

  try {
    // Case 1: already valid JSON
    previousMetrics = typeof raw === "string" ? JSON.parse(raw) : raw;
  } catch (e1) {
    try {
      // Case 2: double-escaped JSON from Sheets
      const unescaped = raw.replace(/\\"/g, '"');
      previousMetrics = JSON.parse(unescaped);
    } catch (e2) {
      // Final fallback: do NOT crash pipeline
      previousMetrics = {};
    }
  }
}

// ---- Delta calculation ----
const deltas = {};

for (const key of Object.keys(currentMetrics)) {
  const currentValue = Number(currentMetrics[key]) || 0;
  const previousValue = Number(previousMetrics[key]) || 0;

  const absoluteDelta = currentValue - previousValue;
  const percentChange =
    previousValue !== 0
      ? Number(((absoluteDelta / previousValue) * 100).toFixed(1))
      : 0;

  deltas[key] = {
    current_value: currentValue,
    previous_value: previousValue,
    absolute_delta: absoluteDelta,
    percent_change: percentChange,
    direction:
      absoluteDelta > 0 ? "↑" :
      absoluteDelta < 0 ? "↓" : "→"
  };
}

// ---- Output ----
return [
  {
    json: {
      current_metrics: currentMetrics,
      previous_metrics: previousMetrics,
      deltas,
      report_date: previousItem?.["Report Date"] || null,
      generated_at: new Date().toISOString()
    }
  }
];

const items = $input.all();

// ---- Identify inputs safely ----
const historyItem = items.find(i => i.json?.["Metrics JSON"]);
const currentItem = items.find(i => i.json?.current_metrics);

// ---- Parse historical metrics (optional) ----
let historicalMetrics = {};
let reportDate = null;

if (historyItem) {
  reportDate = historyItem.json["Report Date"] || null;

  const raw = historyItem.json["Metrics JSON"];
  if (raw) {
    try {
      historicalMetrics =
        typeof raw === "string"
          ? JSON.parse(raw.replace(/\\"/g, '"'))
          : raw;
    } catch {
      historicalMetrics = {};
    }
  }
}

// ---- Current metrics (required for trends) ----
let currentMetrics = {};
let deltas = {};

if (currentItem) {
  currentMetrics = currentItem.json.current_metrics || {};
  deltas = currentItem.json.deltas || {};
}

// ---- If no current metrics, return safe noop ----
if (!currentItem) {
  return [
    {
      json: {
        trends: {},
        status: "skipped",
        reason: "No current metrics available",
        generated_at: new Date().toISOString()
      }
    }
  ];
}

// ---- Trend detection (2-point comparison) ----
const trends = {};

for (const metric of Object.keys(currentMetrics)) {
  const curr = Number(currentMetrics[metric]);
  const prev = Number(historicalMetrics[metric]);

  if (Number.isNaN(curr)) continue;

  let trend_label = "flat";
  let trend_score = 0;

  if (!Number.isNaN(prev)) {
    if (curr > prev) {
      trend_label = "uptrend";
      trend_score = 1;
    } else if (curr < prev) {
      trend_label = "downtrend";
      trend_score = -1;
    }
  } else {
    trend_label = "new_metric";
  }

  trends[metric] = {
    previous_value: Number.isNaN(prev) ? null : prev,
    current_value: curr,
    absolute_delta: deltas[metric]?.absolute_delta ?? null,
    percent_change: deltas[metric]?.percent_change ?? null,
    direction: deltas[metric]?.direction ?? "→",
    trend_label,
    trend_score
  };
}

// ---- Output (always 1 item) ----
return [
  {
    json: {
      trends,
      report_date: reportDate || currentItem.json.report_date || null,
      generated_at: new Date().toISOString(),
      status: historyItem ? "full_comparison" : "partial_comparison"
    }
  }
];

