const item = $input.all()[0]?.json || {};

// ---- Safe JSON parsing helper ----
function safeParse(value, fallback = {}) {
  if (!value) return fallback;
  if (typeof value === "object") return value;
  try {
    return JSON.parse(value.replace(/\\"/g, '"'));
  } catch {
    return fallback;
  }
}

// ---- Normalize to array helper ----
function toArray(value) {
  if (!value) return [];
  return Array.isArray(value) ? value : [value];
}

// ---- Parse analysis (handles string/object) ----
const analysis = safeParse(item);

// ---- Normalize fields ----
const whatsWorking = toArray(analysis.whats_working);
const whatsConcerning = toArray(analysis.whats_concerning);
const trendAnalysis = toArray(analysis.trend_analysis);
const focusAreas = toArray(analysis.recommended_focus_areas);
const blindSpots = toArray(analysis.blind_spots);

// ---- Build report ----
let report = `# 📊 Business Health Monitor – Weekly Report\n\n`;
report += `**Week Ending:** ${new Date().toISOString().split("T")[0]}\n`;
report += `**Overall Health Score:** ${analysis.overall_health_score ?? "N/A"}/100\n`;
report += `**Confidence Level:** ${analysis.confidence_level ?? "N/A"}\n\n`;

report += `---\n\n`;
report += `## 🔍 Executive Pulse\n\n`;
report += `${analysis.executive_summary ?? "No executive summary available."}\n\n`;

report += `---\n\n`;
report += `## ✅ What's Working\n\n`;
if (whatsWorking.length === 0) {
  report += `- No strong positive signals identified this week.\n\n`;
} else {
  for (const item of whatsWorking) {
    report += `### ${item.signal ?? "Positive Signal"}\n`;
    report += `- **Evidence:** ${item.evidence ?? "N/A"}\n`;
    report += `- **Significance:** ${item.significance ?? "N/A"}\n`;
    report += `- **Momentum:** ${item.momentum ?? "N/A"}\n\n`;
  }
}

report += `---\n\n`;
report += `## ⚠️ What's Concerning\n\n`;
if (whatsConcerning.length === 0) {
  report += `- No critical risks detected.\n\n`;
} else {
  for (const item of whatsConcerning) {
    report += `### ${item.signal ?? "Risk Signal"}\n`;
    report += `- **Evidence:** ${item.evidence ?? "N/A"}\n`;
    report += `- **Severity:** **${item.severity ?? "Unknown"}**\n`;
    report += `- **Likely Cause:** ${item.likely_cause ?? "N/A"}\n`;
    report += `- **Watch Next:** ${item.leading_indicator ?? "N/A"}\n\n`;
  }
}

report += `---\n\n`;
report += `## 📈 Trend Analysis\n\n`;
if (trendAnalysis.length === 0) {
  report += `- No clear trend patterns available.\n\n`;
} else {
  for (const item of trendAnalysis) {
    report += `**${item.metric ?? "Metric"}** → ${item.current_trend ?? "flat"}\n`;
    report += `${item.business_meaning ?? ""}\n\n`;
  }
}

report += `---\n\n`;
report += `## 🎯 Where to Focus Next Week\n\n`;
if (focusAreas.length === 0) {
  report += `- No specific focus areas identified.\n\n`;
} else {
  for (const item of focusAreas) {
    const icon =
      item.priority === "P1" ? "🔴" :
      item.priority === "P2" ? "🟡" : "🟢";

    report += `${icon} **${item.area ?? "Focus Area"}** (${item.effort ?? "unknown"} effort)\n`;
    report += `→ Expected impact: ${item.expected_impact ?? "N/A"}\n\n`;
  }
}

report += `---\n\n`;
report += `## 💡 Blind Spots\n\n`;
if (blindSpots.length === 0) {
  report += `- No blind spots identified.\n`;
} else {
  for (const spot of blindSpots) {
    report += `- ${spot}\n`;
  }
}

report += `\n---\n\n`;
report += `*Generated by AI Business Health Monitor*\n`;
report += `*Confidence rationale: ${analysis.confidence_rationale ?? "N/A"}*\n`;

// ---- Output ----
return [
  {
    json: {
      markdown_report: report,
      analysis
    }
  }
];
